// Solution
function fixPortMappings(portMappings) {
  let correctedMappings = [];
  let mappings = portMappings.split(',');
  for (let mapping of mappings) {
    let [exposed, container] = mapping.split(':').map(Number);
    let correctedMapping = exposed > container ? `${exposed}:${container}` : `${container}:${exposed}`;
    correctedMappings.push(correctedMapping);
  }
  return correctedMappings;
}

