class Solution:
  def fixPortMappings(self, portMappings: str) -> list[str):
    correctedMappings = []
    mappings = portMappings.split(',')
    for mapping in mappings:
      exposed, container = mapping.split(':').map(int)
      correctedMapping = f'{exposed}:{container}' if exposed > container else f'{container}:{exposed}'
      correctedMappings.append(correctedMapping)
    return correctedMappings
